    /* ================= PAGINATION (Mahsulot > 20) ================= */
    const PAGE_SIZE = 20; // если на странице всегда 20

    function hasPagination() {
      return !!document.querySelector('nav[aria-label*="pagination"]');
    }

    async function waitMahsulotUI(timeout = 30000) {
      // ждём пока исчезнет спиннер (если он есть)
      await waitFor(() => !document.querySelector('.MuiCircularProgress-root'), timeout, 150);

      // ждём кнопки Qo'shish (главный признак что список уже отрисован)
      const ok = await waitFor(() => getQoshishButtons().length > 0, timeout, 150);

      // иногда пагинация появляется чуть позже
      await waitFor(() => hasPagination() || getQoshishButtons().length > 0, 8000, 150);

      return ok;
    }

    function getQoshishButtons() {
      return [...document.querySelectorAll('button')]
        .filter(b => b.textContent.trim() === "Qo'shish");
    }

    async function waitQoshishReady(timeout = 20000) {
      const ok = await waitFor(() => getQoshishButtons().length > 0, timeout, 120);
      return ok;
    }

    function getPageButtons() {
      // MUI Pagination: кнопки страниц
      return [...document.querySelectorAll('nav[aria-label*="pagination"] button')]
        .filter(b => b && b.textContent && b.textContent.trim().match(/^\d+$/));
    }

    function getCurrentPageNumber() {
      // MUI обычно ставит aria-current="true" на выбранную кнопку
      const cur = document.querySelector('nav[aria-label*="pagination"] button[aria-current="true"]')
               || document.querySelector('nav[aria-label*="pagination"] button.Mui-selected');
      const t = cur?.textContent?.trim();
      const n = parseInt(t || '', 10);
      return Number.isFinite(n) ? n : 1;
    }

    function findNextPageBtn() {
      // В твоём скрине есть aria-label="Go to next page"
      return document.querySelector('button[aria-label="Go to next page"]')
          || document.querySelector('button[aria-label*="next page"]')
          || document.querySelector('button[aria-label*="След"]') // на случай RU
          || document.querySelector('button[aria-label*="Keyingi"]'); // на случай UZ
    }

    async function goToPage(targetPage) {
      await waitMahsulotUI(35000);

      targetPage = Math.max(1, targetPage);

      // если уже на этой странице — просто ждём список
      if (getCurrentPageNumber() === targetPage) {
        await waitQoshishReady(20000);
        return true;
      }

      // 1) пробуем клик по конкретной цифре страницы
      const pageBtns = getPageButtons();
      const direct = pageBtns.find(b => parseInt(b.textContent.trim(), 10) === targetPage);

      if (direct) {
        const prevPage = getCurrentPageNumber();
        direct.scrollIntoView({ block: 'center' });
        direct.click();

        // ✅ ждём, что номер страницы реально поменялся
        await waitFor(() => getCurrentPageNumber() !== prevPage, 15000, 120);

        // ✅ ждём появления кнопок Qo'shish
        await waitQoshishReady(20000);
        return true;
      }

      // 2) иначе листаем next пока не дойдём
      let guard = 50;
      while (guard-- > 0) {
        const cur = getCurrentPageNumber();
        if (cur === targetPage) {
          await waitQoshishReady(20000);
          return true;
        }

        const nextBtn = findNextPageBtn();
        if (!nextBtn || nextBtn.disabled) return false;

        const prevPage = cur;
        nextBtn.scrollIntoView({ block: 'center' });
        nextBtn.click();

        await waitFor(() => getCurrentPageNumber() !== prevPage, 15000, 120);
        await waitQoshishReady(20000);
      }

      return false;
    }

    async function ensureMahsulotVisible(globalMahsulotNo) {
      const m = parseInt(String(globalMahsulotNo), 10);
      if (!Number.isFinite(m) || m <= 0) return { ok: false, page: 1, indexInPage: 1 };

      const targetPage = Math.ceil(m / PAGE_SIZE);
      const indexInPage = ((m - 1) % PAGE_SIZE) + 1;

      // если страница уже та — ок
      const cur = getCurrentPageNumber();
      if (cur !== targetPage) {
        const ok = await goToPage(targetPage);
        return { ok, page: targetPage, indexInPage };
      }

      return { ok: true, page: targetPage, indexInPage };
    }

