    async function runExcelImport() {
        const input = document.createElement('input');
        input.type = 'file';
        input.accept = '.xlsx';

        input.onchange = async e => {EXCEL_RUNNING = true;
EXCEL_STOP = false;
setExcelButtonsState();
setExcelProgress('📥 Читаю Excel...');
            const data = new Uint8Array(await e.target.files[0].arrayBuffer());
            const wb = XLSX.read(data, { type: 'array' });
            const sheet = wb.Sheets[wb.SheetNames[0]];
            const rows = XLSX.utils.sheet_to_json(sheet, { header: 1 });

            const dataRows = rows.slice(1).filter(r => r.length >= 7);

            for (const row of dataRows) {
                await excelFillRow(row);
                await sleep(s(400));
            }
        };

        input.click();
    }

    /* ================= EXCEL -> AUTOFILL (Soni / O'lchov / Shablon / Lab) ================= */

    function normHeader(s) {
      return (s || '')
        .toString()
        .trim()
        .toLowerCase()
        .replace(/\s+/g, ' ')
        .replace(/[`’‘]/g, "'")
        .replace(/№/g, 'no');
    }

    function findColIndex(headers, variants) {
      const h = headers.map(normHeader);
      for (const v of variants) {
        const idx = h.indexOf(normHeader(v));
        if (idx !== -1) return idx;
      }
      return -1;
    }

    function findColsByPrefix(headers, prefixes) {
      // prefixes: ['shablon', 'shablonlar'] или ['laboratoriya','sinov laboratoriyalari']
      const h = headers.map(normHeader);
      const out = [];
      for (let i = 0; i < h.length; i++) {
        for (const p of prefixes) {
          const pp = normHeader(p);
          if (h[i].startsWith(pp)) {
            // ловим: "shablon 1", "shablon2", "laboratoriya 3" и т.д.
            out.push(i);
            break;
          }
        }
      }
      // чтобы был порядок 1..N (если в шапке есть цифры)
      out.sort((a,b) => a-b);
      return out;
    }

    function splitMultiCell(v) {
      // разрешаем разделители: \n ; , |
      const s = safeText(v);
      if (!s) return [];
      return s
        .split(/\n|;|,|\|/g)
        .map(x => x.trim())
        .filter(Boolean);
    }

    function uniq(arr) {
      const seen = new Set();
      const out = [];
      for (const x of arr) {
        const k = String(x).trim();
        if (!k || seen.has(k)) continue;
        seen.add(k);
        out.push(k);
      }
      return out;
    }

    function isNumericLab(x) {
      const t = (x ?? '').toString().trim();
      return /^[0-9]{2,6}$/.test(t) || /^[0-9]{2,6}\s*\/\s*[0-9]{2,6}$/.test(t);
    }

