let LOG_MAX = 160;

function ensureLogUI() {
  const box = document.querySelector('#tmLog');
  return box || null;
}

function logLine(msg, type = 'info') {
  const box = ensureLogUI();
  const ts = new Date().toLocaleTimeString();

  const line = document.createElement('div');
  line.className = 'tm-log-line tm-' + type;
  line.textContent = `[${ts}] ${msg}`;

  if (box) {
    box.appendChild(line);
    // ограничение по строкам
    while (box.childNodes.length > LOG_MAX) box.removeChild(box.firstChild);
    box.scrollTop = box.scrollHeight;
  }

  // в консоль тоже полезно
  if (type === 'err') console.warn('TM:', msg);
  else console.log('TM:', msg);
}

function logClear() {
  const box = ensureLogUI();
  if (box) box.innerHTML = '';
}

function logDivider(title = '') {
  logLine(title ? `──────── ${title} ────────` : '────────────────────────', 'dim');
}

