    /* ================= MULTI: Shablon + Lab (one-by-one with Saqlash) ================= */

   function pickManyFixed5ByPrefixNumber(r, headers, prefixVariants) {
  // Возвращает массив длиной 5: [col1, col2, col3, col4, col5]
  const h = headers.map(normHeader);
  const out = ['', '', '', '', ''];

  for (let col = 0; col < h.length; col++) {
    const name = h[col]; // например "laboratoriya 3"
    for (const p of prefixVariants) {
      const pref = normHeader(p);

      // ловим: "laboratoriya 3", "laboratoriya3", "laboratoriya  3"
      const m = name.match(new RegExp('^' + pref + '\\s*(\\d+)\\b'));
      if (!m) continue;

      const n = parseInt(m[1], 10);
      if (!Number.isFinite(n) || n < 1 || n > 5) continue;

      out[n - 1] = safeText(r[col]); // НЕ выкидываем пустые
    }
  }
  return out; // длина всегда 5
}

    async function openMahsulotDialogByNo(mahsulotNo) {
      const uiOk = await waitMahsulotUI(35000);
      if (!uiOk) throw new Error("Mahsulot UI not ready");

      const nav = await ensureMahsulotVisible(mahsulotNo);
      if (!nav.ok) throw new Error("Cannot navigate to mahsulot page");

      const ready = await waitQoshishReady(25000);
      if (!ready) throw new Error("Qo'shish buttons not ready");

      const qoshishBtns = getQoshishButtons();
      const target = qoshishBtns[nav.indexInPage - 1];
      if (!target) throw new Error("Qo'shish target not found");

      target.click();

      // ждём диалог
      let dialog = null;
      const ok = await waitFor(() => {
        dialog = [...document.querySelectorAll('div[role="dialog"]')].pop();
        return !!dialog;
      }, 20000, 120);

      if (!ok || !dialog) throw new Error("Dialog not opened");
      return dialog;
    }

    async function fillDialogCommonFields(dialog, cfg) {
      // Soni
      const soni = [...dialog.querySelectorAll('label')]
        .find(l => l.textContent.includes('Soni'))
        ?.closest('.MuiFormControl-root')
        ?.querySelector('input');
      if (soni) reactSet(soni, cfg.soni);

      // O‘lchov
      const olchovAuto = [...dialog.querySelectorAll('.MuiAutocomplete-root')]
        .find(a => a.textContent.includes("O'lchov") || a.textContent.includes("O`lchov") || a.textContent.includes("O‘lchov"));
      if (olchovAuto && cfg.olchov) await selectAutocomplete(olchovAuto, cfg.olchov);
    }

    async function selectOneShablon(dialog, shablonValue) {
      if (!shablonValue) return;

      if (MANUAL_TEMPLATE) {
        // если ручной выбор — просто кликаем по заранее сохранённому элементу
        MANUAL_TEMPLATE.scrollIntoView({ block: 'center' });
        MANUAL_TEMPLATE.click();
        await sleep(s(200));
        return;
      }

      const shablonAuto = [...dialog.querySelectorAll('.MuiAutocomplete-root')]
        .find(a => a.textContent.includes('Shablon'));
      if (!shablonAuto) return;

      const input = shablonAuto.querySelector('input');
      if (!input) return;

      input.focus();
      reactSet(input, shablonValue);
      await sleep(s(80));
      await muiSelectFirstOptionByClick(input);
       await muiPickHard(input, shablonValue, { match:'contains' });

    }

    async function selectOneLab(dialog, labValue) {
      if (!labValue) return;

      const labSearch = dialog.querySelector('input[type="search"]');
      if (!labSearch) return;

      labSearch.focus();
      reactSet(labSearch, labValue);
      await sleep(s(80));

      // если число/код — быстрее через результаты
      let ok = false;
      if (MANUAL_CHECKBOX) {
        MANUAL_CHECKBOX.scrollIntoView({ block: 'center' });
        MANUAL_CHECKBOX.click();
        ok = true;
      } else {
        // если это текст (не номер) — точный текст, иначе по единственному результату
        ok = isNumericLab(labValue)
          ? await clickLabCheckboxFromSearchResults(dialog)
          : await clickLabCheckboxByExactText(dialog, labValue);
      }
      if (!ok) console.warn('⚠️ Лаборатория не выбрана:', labValue);
    }

   async function saveAndWaitClose(dialog) {
  await retry(async () => {
    const saveBtn = [...dialog.querySelectorAll('button')]
      .find(b => b.textContent.trim().toLowerCase() === 'saqlash' && !b.disabled);

    if (!saveBtn) throw new Error("Saqlash button not ready");

    clickUser(saveBtn);

    const closed = await waitFor(() => !document.body.contains(dialog), 25000, 120);
    if (!closed) throw new Error("Dialog did not close after Saqlash");
    return true;
  }, { tries: 6, delay: 450, maxDelay: 6000, label: "saveAndWaitClose" });
}


   async function runMahsulotMulti(cfg, shablonList, labList) {
  logDivider(`Mahsulot №${cfg.mahsulot}`);
  logLine(`Soni="${cfg.soni}"  Olchov="${cfg.olchov}"`, 'dim');

  const S = (shablonList || []).map(x => (x ?? '').toString().trim()).filter(Boolean);
  const L = (labList    || []).map(x => (x ?? '').toString().trim()).filter(Boolean);

  // fallback: одиночные поля
  if (!S.length && !L.length) {
    const fallbackSh = (cfg.shablon || '').toString().trim();
    const fallbackLb = (cfg.labNumber || '').toString().trim();

    await retry(async () => {
      const dialog = await openMahsulotDialogByNo(cfg.mahsulot);
      await fillDialogCommonFields(dialog, cfg);

      if (fallbackSh) await selectOneShablon(dialog, fallbackSh);
      if (fallbackLb) await selectOneLab(dialog, fallbackLb);

      await saveAndWaitClose(dialog);
      logLine(`  💾 Saqlash OK (fallback)`, 'ok');
      return true;
    }, { tries: 8, delay: 600, maxDelay: 5000, label: `Mahsulot#${cfg.mahsulot} fallback` });

    await sleep(s(120));
    return;
  }

  const n = Math.max(S.length, L.length);

  for (let i = 0; i < n; i++) {
    const sh = S[i] ?? S[S.length - 1] ?? '';
    const lb = L[i] ?? L[L.length - 1] ?? '';

    if (!sh && !lb) {
      logLine(`Пара ${i+1}/${n}: пусто → пропуск`, 'warn');
      continue;
    }

    logLine(`Пара ${i+1}/${n}: Shablon="${sh}" | Lab="${lb}"`, 'info');
    setExcelProgress?.(`🧱 Mahsulot №${cfg.mahsulot}: пара ${i + 1}/${n}`);

    await retry(async () => {
      const dialog = await openMahsulotDialogByNo(cfg.mahsulot);
      await fillDialogCommonFields(dialog, cfg);

      if (sh) await selectOneShablon(dialog, sh);
      if (lb) await selectOneLab(dialog, lb);

      await saveAndWaitClose(dialog);
      logLine(`  💾 Saqlash OK (пара ${i+1})`, 'ok');
      return true;
    }, { tries: 8, delay: 600, maxDelay: 5000, label: `Mahsulot#${cfg.mahsulot} pair ${i + 1}` });

    await sleep(s(120));
  }
}


    async function runExcelAutofill() {
      const input = document.createElement('input');
      input.type = 'file';
      input.accept = '.xlsx,.xls';

      input.onchange = async (e) => {
        const file = e.target.files?.[0];
        if (!file) return;

        EXCEL_RUNNING = true;
        EXCEL_STOP = false;
        setExcelButtonsState();
        setExcelProgress('📥 Читаю Excel...');

        try {
          const data = new Uint8Array(await file.arrayBuffer());
          const wb = XLSX.read(data, { type: 'array' });
          const sheet = wb.Sheets[wb.SheetNames[0]];
          const rows = XLSX.utils.sheet_to_json(sheet, { header: 1, raw: false });

          if (!rows || rows.length < 2) {
            alert('❌ В Excel нет данных (нужна шапка + строки)');
            setExcelProgress('❌ В Excel нет данных');
            return;
          }

          const headers = rows[0];

          const cNo = findColIndex(headers, ['no', '№', 'n', 'номер', 'mahsulot', 'mahsulot №']);
          const cSoni = findColIndex(headers, ['soni', 'количество', 'кол-во']);
          const cOlchov = findColIndex(headers, ["o'lchov birligi", "o`lchov birligi", "o‘lchov birligi", 'единица измерения', 'ед. измерения']);
          const cShablon = findColIndex(headers, ['shablonlar', 'shablon', 'шаблон', 'шаблоны']);
          const cLab = findColIndex(headers, ['sinov laboratoriyalari', 'sinov laboratoriyasi', 'лаборатория', 'испытательная лаборатория', 'испытательные лаборатории']);

          if (cNo === -1) {
            alert("❌ Не найден столбец № (No). Он нужен, чтобы понять какой Mahsulot заполнять.");
            setExcelProgress('❌ Нет столбца № (No)');
            return;
          }

          // ✅ ВАЖНО: МНОГОКОЛОНОЧНЫЕ "Shablon 1..", "Laboratoriya 1.." — ОПРЕДЕЛЯЕМ ЗАРАНЕЕ (исправление бага)
          const cShablonMany = findColsByPrefix(headers, ['shablon', 'shablonlar']);
          const cLabMany     = findColsByPrefix(headers, ['laboratoriya', 'sinov laboratoriyalari', 'sinov laboratoriyasi', 'лаборатория', 'lab']);

          // Берём только строки где есть №
          const dataRows = rows
            .slice(1)
            .map(r => (Array.isArray(r) ? r : []))
            .filter(r => safeText(r[cNo]) !== '');

          if (!dataRows.length) {
            alert('❌ В Excel нет строк с №');
            setExcelProgress('❌ Нет строк с №');
            return;
          }

          const total = dataRows.length;
          setExcelProgress(`✅ Excel загружен. Строк: ${total}. Начинаю...`);

          // Идём построчно
          for (let k = 0; k < total; k++) {
            if (EXCEL_STOP) {
              setExcelProgress(`⛔ Остановлено пользователем на ${k}/${total}`);
              break;
            }

            setExcelProgress(`⚙️ Mahsulot ${k + 1}/${total} заполняется...`);

            const r = dataRows[k];
            const mahsulotNo = parseInt(safeText(r[cNo]), 10);
            if (isNaN(mahsulotNo) || mahsulotNo <= 0) {
              // пропускаем, но прогресс идёт дальше
              await sleep(250);
              continue;
            }

            // ✅ собираем значения из Shablon 1..N и Lab 1..N
            const templatesFromCols = [];
            for (const ci of cShablonMany) templatesFromCols.push(safeText(r[ci]));
            const labsFromCols = [];
            for (const ci of cLabMany) labsFromCols.push(safeText(r[ci]));

            const cfg = {
              mahsulot: mahsulotNo,
              soni: safeText(cSoni !== -1 ? r[cSoni] : ''),
              olchov: safeText(cOlchov !== -1 ? r[cOlchov] : ''),
              // одиночные поля (на всякий)
              shablon: safeText(cShablon !== -1 ? r[cShablon] : ''),
              labNumber: safeText(cLab !== -1 ? r[cLab] : ''),
              labText: safeText(cLab !== -1 ? r[cLab] : ''),
              // ✅ массивы (главное)
              templates: uniq([
                ...templatesFromCols.flatMap(splitMultiCell),
                safeText(cShablon !== -1 ? r[cShablon] : '')
              ]),
              labs: uniq([
                ...labsFromCols.flatMap(splitMultiCell),
                safeText(cLab !== -1 ? r[cLab] : '')
              ])
            };

            // ✅ multi lists from Excel advanced template
            const shList = pickManyFixed5ByPrefixNumber(r, headers, ['shablon', 'shablonlar']);
const lbList = pickManyFixed5ByPrefixNumber(r, headers, ['laboratoriya', 'lab', 'sinov laboratoriyalari', 'sinov laboratoriyasi']);

await runMahsulotMulti(cfg, shList, lbList);

            if (EXCEL_STOP) {
              setExcelProgress(`⛔ Остановлено пользователем на ${k + 1}/${total}`);
              break;
            }
// ✅ каждые 8 товаров — короткая передышка (сервер/интернет)
if ((k + 1) % 8 === 0) {
  await sleep(s(250));
}

            // ✅ оставили твой старый кусок, но чтобы НЕ было конфликта const — переименовали
            const cShablonMany__old = findColsByPrefix(headers, ['shablon', 'shablonlar']);
            const cLabMany__old     = findColsByPrefix(headers, ['laboratoriya', 'sinov laboratoriyalari', 'sinov laboratoriyasi', 'лаборатория']);

            // пауза между строками — если интернет слабый, это спасает от срывов
          await sleep(s(220));
          }

          if (!EXCEL_STOP) {
            alert('✅ Excel импорт завершён');
            setExcelProgress('✅ Готово! Автозаполнение завершено.');
          }

        } catch (err) {
          console.error(err);
          alert('❌ Ошибка чтения Excel / автозаполнения. См. Console.');
          setExcelProgress('❌ Ошибка. Открой Console (F12)');
        } finally {
          EXCEL_RUNNING = false;
          setExcelButtonsState();
        }
      };

      input.click();
    }

    /* ================= ACT AUTOFILL (2-step) ================= */

    function normUiText(s) {
      return (s || '')
        .toString()
        .trim()
        .toLowerCase()
        .replace(/\s+/g, ' ')
        .replace(/[’‘`´ʻʼ]/g, "'")
        .replace(/o‘/g, "o'")     // иногда узбекская кавычка
        .replace(/o’/g, "o'");
    }

    function findInputByLabel(root, labelText) {
      const needle = normUiText(labelText);
      const scope = root || document;

      // 1) Ищем <label> по тексту
      const labels = [...scope.querySelectorAll('label')];
      const lab = labels.find(l => normUiText(l.innerText).includes(needle));

      if (lab) {
        // 1a) Если есть for -> id
        const forId = lab.getAttribute('for');
        if (forId) {
          const byId = document.getElementById(forId);
          if (byId) return byId;
        }

        // 1b) Если внутри label лежит input/textarea
        const inside = lab.querySelector('input, textarea');
        if (inside) return inside;

        // 1c) Ищем рядом по структуре MUI
        const wrap =
          lab.closest('.MuiFormControl-root') ||
          lab.closest('.MuiGrid-item') ||
          lab.closest('.MuiInputBase-root') ||
          lab.parentElement;

        if (wrap) {
          const field = wrap.querySelector('textarea, input');
          if (field) return field;
        }
      }

      // 2) Фолбэк: ищем элементы текста рядом (p/span/div) как ты делал, но с нормализацией
      const candidates = [...scope.querySelectorAll('p, span, div')]
        .filter(el => el && el.innerText)
        .map(el => ({ el, txt: normUiText(el.innerText) }))
        .filter(x => x.txt.includes(needle));

      const hit = candidates[0]?.el;
      if (hit) {
        const wrap =
          hit.closest('.MuiFormControl-root') ||
          hit.closest('.MuiGrid-item') ||
          hit.closest('.MuiInputBase-root') ||
          hit.parentElement;

        if (wrap) {
          const field = wrap.querySelector('textarea, input');
          if (field) return field;
        }
      }

      return null;
    }

    function clickVisibleSave(root) {
      const btn = [...root.querySelectorAll('button')]
        .filter(b => (b.textContent || '').trim().toLowerCase() === 'saqlash')
        .filter(b => !b.disabled)
        .filter(b => b.offsetParent !== null)[0];

      if (!btn) return false;

      btn.scrollIntoView({ block: 'center' });
      btn.dispatchEvent(new MouseEvent('mousedown', { bubbles: true }));
      btn.dispatchEvent(new MouseEvent('mouseup', { bubbles: true }));
      btn.click();
      return true;
    }

    function getLastDialog() {
      return [...document.querySelectorAll('div[role="dialog"]')].pop() || null;
    }
    async function waitDialog(timeout = 20000) {
      return await waitFor(() => [...document.querySelectorAll('div[role="dialog"]')].pop(), timeout, 120);
    }

    function isVisible(el) {
      return !!(el && el.offsetParent !== null);
    }

    function clickTopSaveActSmart() {
      const part = document.querySelector('textarea[name="part_result"]');
      if (!part) return false;

      // чтобы MUI "зафиксировал" изменения
      part.focus();
      part.dispatchEvent(new Event('blur', { bubbles: true }));

      const partRect = part.getBoundingClientRect();

      // все видимые "Saqlash" вне диалогов
      const btns = [...document.querySelectorAll('button')]
        .filter(b => (b.textContent || '').trim().toLowerCase() === 'saqlash')
        .filter(b => !b.disabled)
        .filter(b => b.offsetParent !== null)
        .filter(b => !b.closest('div[role="dialog"]'));

      if (!btns.length) {
        console.warn('❌ Не нашёл ни одной видимой кнопки Saqlash (верх)');
        return false;
      }

      // если есть таблица — верхняя кнопка обычно ВЫШЕ таблицы
      const table = document.querySelector('table');
      const tableTop = table ? table.getBoundingClientRect().top : Infinity;

      // выбираем лучшую кнопку: выше таблицы + ближе к верхней форме
      let best = null;
      let bestScore = Infinity;

      for (const b of btns) {
        const r = b.getBoundingClientRect();

        // отсекаем нижний Saqlash у таблицы
        if (r.top > tableTop - 10) continue;

        const dy = Math.abs(r.top - partRect.bottom);
        const dx = Math.abs(r.left - partRect.right);
        const score = dy * 1.0 + dx * 0.15;

        if (score < bestScore) {
          bestScore = score;
          best = b;
        }
      }

      // если фильтр по таблице всё выкинул — берём просто ближайшую
      if (!best) {
        for (const b of btns) {
          const r = b.getBoundingClientRect();
          const dy = Math.abs(r.top - partRect.bottom);
          const dx = Math.abs(r.left - partRect.right);
          const score = dy * 1.0 + dx * 0.15;

          if (score < bestScore) {
            bestScore = score;
            best = b;
          }
        }
      }

      if (!best) return false;

      best.scrollIntoView({ block: 'center' });

      // ✅ клик как пользователь (MUI любит pointer events)
      best.dispatchEvent(new PointerEvent('pointerdown', { bubbles: true }));
      best.dispatchEvent(new MouseEvent('mousedown', { bubbles: true }));
      best.dispatchEvent(new PointerEvent('pointerup', { bubbles: true }));
      best.dispatchEvent(new MouseEvent('mouseup', { bubbles: true }));
      best.click();

      // ✅ если submit — пробуем requestSubmit по реальной форме
      try {
        const form =
          (best.form) ||
          best.closest('form') ||
          document.querySelector(`form:has(button[type="submit"])`); // fallback

        if (form && typeof form.requestSubmit === 'function') {
          form.requestSubmit(best);
        }
      } catch (e) {}

      return true;
    }

    function findRowByNo(no) {
      const n = String(no).trim();
      const rows = [...document.querySelectorAll('table tbody tr')];
      for (const tr of rows) {
        const tds = [...tr.querySelectorAll('td')];
        if (!tds.length) continue;
        const first = (tds[0].innerText || '').trim();
        if (first === n) return tr;
      }
      return null;
    }

    function clickPlusInRow(tr) {
      if (!tr) return false;

      // чаще всего плюс — это IconButton в последнем td
      const lastTd = tr.querySelector('td:last-child') || tr;
      const btn =
        lastTd.querySelector('button') ||
        [...lastTd.querySelectorAll('button')].pop();

      if (!btn) return false;

      btn.scrollIntoView({ block: 'center' });
      btn.click();
      return true;
    }

