function injectMotionBlurCSS() {
  if (document.getElementById('tm_motion_blur_css')) return;
  const st = document.createElement('style');
  st.id = 'tm_motion_blur_css';
  st.textContent = `
    #toolsBtn.tm-dragging { will-change: transform, filter; }

    #toolsBtn.tm-dragging::after{
      content:"";
      position:absolute;
      inset:-6px;
      border-radius: inherit;
      pointer-events:none;
      opacity:0.55;
      filter: blur(10px);
      background: radial-gradient(closest-side, rgba(255,140,0,.65), rgba(255,0,0,0));
      mix-blend-mode: screen;
    }

    /* ===== Trail copies ===== */
    .tm-trail {
      position: fixed;
      z-index: 999998;
      pointer-events: none;
      border-radius: 14px;
      overflow: hidden;
      will-change: transform, opacity, filter;
      mix-blend-mode: screen;
      animation: tmTrailFade 260ms ease-out forwards;
      opacity: .75;
      filter: blur(2px);
    }

    .tm-trail::before{
      content:"";
      position:absolute;
      inset:-2px;
      background: conic-gradient(from 0deg,
        rgba(255,210,90,.9),
        rgba(255,120,0,.9),
        rgba(210,0,0,.9),
        rgba(255,120,0,.9),
        rgba(255,210,90,.9)
      );
      filter: blur(10px);
      opacity:.55;
    }

    .tm-trail::after{
      content:"";
      position:absolute;
      inset:2px;
      border-radius:12px;
      background: linear-gradient(180deg, rgba(255,140,0,.20), rgba(0,0,0,.0));
      opacity:.8;
    }

    @keyframes tmTrailFade {
      from { opacity: .75; transform: translateZ(0) scale(1); }
      to   { opacity: 0;   transform: translateZ(0) scale(1.08); filter: blur(10px); }
    }
  `;
  document.head.appendChild(st);
}

let TM_TRAIL_LAST = 0;

function spawnDragTrail(btn) {
  const now = performance.now();
  // throttle: максимум ~20 следов/сек
  if (now - TM_TRAIL_LAST < 50) return;
  TM_TRAIL_LAST = now;

  const r = btn.getBoundingClientRect();

  const t = document.createElement('div');
  t.className = 'tm-trail';
  t.style.left = r.left + 'px';
  t.style.top = r.top + 'px';
  t.style.width = r.width + 'px';
  t.style.height = r.height + 'px';

  document.body.appendChild(t);
  t.addEventListener('animationend', () => t.remove(), { once: true });

  // страховка, если animationend не сработал
  setTimeout(() => t.remove(), 800);
}

function applyDragBlur(handle, speedPxPerMs) {
  const speed = Math.min(2.2, Math.max(0, speedPxPerMs));
  const blur = Math.min(14, Math.round(speed * 10));
  const stretch = Math.min(18, Math.round(speed * 14));

  handle.classList.add('tm-dragging');
  handle.style.filter = `blur(${blur}px) brightness(${1 + speed * 0.12})`;
  handle.style.transform = `translateZ(0) scaleX(${1 + stretch / 200})`;
}

function clearDragBlur(handle) {
  handle.classList.remove('tm-dragging');
  handle.style.filter = '';
  handle.style.transform = '';
}

